 function drawTiledWall(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
-  const wc: Record<CharacterType, [string, string, string]> = {
-    king: ['#3e3650', '#484060', '#353048'], nobility: ['#3a3850', '#44405a', '#323048'],
-    knight: ['#384050', '#404858', '#303848'], squire: ['#384038', '#404840', '#303830'],
-    healer: ['#303850', '#384058', '#282e48'], sentinel: ['#303848', '#3a4050', '#282e40'],
-    scribe: ['#3a3430', '#443c38', '#322c28'], judge: ['#383040', '#403848', '#302838'],
-    blacksmith: ['#383028', '#403830', '#302820'],
-  };
-  const [base, light, dark] = wc[type];
-  ctx.fillStyle = base; ctx.fillRect(x, y, w, h);
-  const bW = 20, bH = 10, seed = x * 7 + y * 13;
-  for (let row = 0; row < Math.ceil(h / bH); row++) {
-    const off = row % 2 === 0 ? 0 : bW * 0.5;
-    for (let col = -1; col < Math.ceil(w / bW) + 1; col++) {
-      const bx = x + col * bW + off, by = y + row * bH;
-      if (bx + bW < x || bx > x + w) continue;
-      const hash = ((bx * 31 + by * 17 + seed) & 0xFF) / 255;
-      ctx.fillStyle = hash > 0.6 ? light : hash > 0.3 ? base : dark;
-      ctx.fillRect(bx + 1, by + 1, bW - 2, bH - 2);
-      ctx.fillStyle = P.dark[1];
-      ctx.fillRect(bx, by, bW, 1);
-      ctx.fillRect(bx, by, 1, bH);
-    }
-  }
-  ctx.fillStyle = 'rgba(255,255,255,0.06)';
-  ctx.fillRect(x, y, w, 2);
+  // Enhanced stone wall rendering with bricks, mortar, depth shading, moss and damage
+  const wc: Record<CharacterType, [string, string, string]> = {
+    king: ['#3e3650', '#484060', '#353048'], nobility: ['#3a3850', '#44405a', '#323048'],
+    knight: ['#384050', '#404858', '#303848'], squire: ['#384038', '#404840', '#303830'],
+    healer: ['#303850', '#384058', '#282e48'], sentinel: ['#303848', '#3a4050', '#282e40'],
+    scribe: ['#3a3430', '#443c38', '#322c28'], judge: ['#383040', '#403848', '#302838'],
+    blacksmith: ['#383028', '#403830', '#302820'],
+  };
+  const [base, light, dark] = wc[type];
+  ctx.fillStyle = base;
+  ctx.fillRect(x, y, w, h);
+
+  const brickWidth = 20;
+  const brickHeight = 10;
+  const mortarColor = '#2a2a2a';
+  const mossColor = 'rgba(40, 80, 30, 0.3)';
+  const damageColor = 'rgba(20, 20, 20, 0.4)';
+  const seed = x * 7 + y * 13;
+
+  for (let row = 0; row < Math.ceil(h / brickHeight); row++) {
+    const offsetX = (row % 2) * (brickWidth / 2);
+    for (let col = -1; col < Math.ceil(w / brickWidth) + 1; col++) {
+      const bx = x + col * brickWidth + offsetX;
+      const by = y + row * brickHeight;
+      if (bx + brickWidth < x || bx > x + w) continue;
+
+      // Brick base color variation
+      const hash = ((bx * 31 + by * 17 + seed) & 0xFF) / 255;
+      let brickColor = hash > 0.6 ? light : hash > 0.3 ? base : dark;
+
+      // Draw brick base
+      ctx.fillStyle = brickColor;
+      ctx.fillRect(bx + 1, by + 1, brickWidth - 2, brickHeight - 2);
+
+      // Draw mortar lines
+      ctx.fillStyle = mortarColor;
+      ctx.fillRect(bx, by, brickWidth, 2); // top mortar line
+      ctx.fillRect(bx, by, 2, brickHeight); // left mortar line
+
+      // Depth shading: add highlight on top-left edges and shadow on bottom-right edges
+      ctx.fillStyle = lightenColor(brickColor, 0.15);
+      ctx.fillRect(bx + 2, by + 2, brickWidth - 4, 1); // highlight top edge
+      ctx.fillRect(bx + 2, by + 2, 1, brickHeight - 4); // highlight left edge
+
+      ctx.fillStyle = shadeColor(brickColor, -15);
+      ctx.fillRect(bx + 2, by + brickHeight - 3, brickWidth - 4, 1); // shadow bottom edge
+      ctx.fillRect(bx + brickWidth - 3, by + 2, 1, brickHeight - 4); // shadow right edge
+
+      // Random moss patches
+      if (hash > 0.7 && Math.random() < 0.2) {
+        ctx.fillStyle = mossColor;
+        ctx.fillRect(bx + 4, by + 3, 6, 4);
+      }
+
+      // Random damage spots
+      if (hash < 0.2 && Math.random() < 0.1) {
+        ctx.fillStyle = damageColor;
+        ctx.fillRect(bx + 8, by + 5, 4, 2);
+      }
+    }
+  }
+
+  // Subtle light reflection on top of wall
+  ctx.fillStyle = 'rgba(255,255,255,0.06)';
+  ctx.fillRect(x, y, w, 2);
+}
